export const getAskGscStreamUrl = () => {




  return `/api/gsc/chat/stream`
}

/**
 * Returns a `text/event-stream` with the following events:
- `meta` — `{ contextSummary: string }` sent once at the start
- `delta` — `{ text: string }` sent for each Claude text chunk
- `done` — `{ ok: true }` sent on success
- `error` — `{ error: string }` sent on failure

The frontend consumes this with `fetch` + a `ReadableStream` reader rather than a generated hook.

 * @summary Stream a Claude reply for the current GSC slice via Server-Sent Events
 */
export const askGscStream = async (gscChatRequest: GscChatRequest, options?: RequestInit): Promise<string> => {

  return customFetch<string>(getAskGscStreamUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      gscChatRequest,)
  }
);}




